#include &lt;netinet/in.h&gt;
#include &lt;arpa/inet.h&gt;
#include &lt;unistd.h&gt;
#include &lt;stdio.h&gt;

int main(void) {
    int srv = socket(AF_INET, SOCK_STREAM, 0);

    int opt = 1;
    setsockopt(srv, SOL_SOCKET, SO_REUSEADDR, &amp;opt, sizeof(opt));

    struct sockaddr_in addr = {
        .sin_family      = AF_INET,
        .sin_addr.s_addr = INADDR_ANY,
        .sin_port        = htons(8080)
    };
    bind(srv, (struct sockaddr *)&amp;addr, sizeof(addr));
    listen(srv, 10);

    struct sockaddr_in cli_addr;
    socklen_t cli_len = sizeof(cli_addr);
    int cli = accept(srv, (struct sockaddr *)&amp;cli_addr, &amp;cli_len);

    printf("Bağlantı: %s\n", inet_ntoa(cli_addr.sin_addr));

    char buf[1024];
    ssize_t n = recv(cli, buf, sizeof(buf) - 1, 0);
    buf[n] = '\0';
    printf("Alındı: %s\n", buf);
    send(cli, "200 OK\r\n", 8, 0);

    close(cli);
    close(srv);
    return 0;
}
</code></pre> UDP Örneği<pre><code>#include &lt;sys/socket.h&gt;
