LED Chase (PORTD)<pre><code>#include &lt;avr/io.h&gt;
#include &lt;util/delay.h&gt;

int main(void) {
    DDRD = 0xFF;   /* Tüm PORTD çıkış */

    while (1) {
        /* Sırayla yak */
        for (uint8_t i = 0; i &lt; 8; i++) {
            PORTD = (1 &lt;&lt; i);
            _delay_ms(100);
        }

        /* Sırayla söndür */
        for (uint8_t i = 0; i &lt; 8; i++) {
            PORTD &amp;= ~(1 &lt;&lt; i);
            _delay_ms(100);
        }
    }
    return 0;
}
</code></pre>

